  'caldav_server_title': {'de': 'Lokaler CalDAV-Server', 'en': 'Local CalDAV server', 'es': 'Servidor CalDAV local', 'fr': 'Serveur CalDAV local', 'hu': 'Helyi CalDAV-kiszolgáló', 'sv': 'Lokal CalDAV-server', 'ar': 'خادم CalDAV محلي', 'he': 'שרת CalDAV מקומי', 'fa': 'سرور CalDAV محلی', 'it': 'Server CalDAV locale', 'pt': 'Servidor CalDAV local', 'nl': 'Lokale CalDAV-server', 'pl': 'Lokalny serwer CalDAV', 'ro': 'Server CalDAV local', 'cs': 'Místní server CalDAV', 'sk': 'Lokálny server CalDAV', 'hr': 'Lokalni CalDAV poslužitelj', 'bg': 'Локален CalDAV сървър', 'el': 'Τοπικός διακομιστής CalDAV', 'da': 'Lokal CalDAV-server', 'fi': 'Paikallinen CalDAV-palvelin', 'no': 'Lokal CalDAV-server', 'uk': 'Локальний CalDAV-сервер', 'ru': 'Локальный сервер CalDAV', 'tr': 'Yerel CalDAV sunucusu', 'zh': '本地 CalDAV 服务器', 'ja': 'ローカル CalDAV サーバー', 'ko': '로컬 CalDAV 서버', 'hi': 'स्थानीय CalDAV सर्वर', 'th': 'เซิร์ฟเวอร์ CalDAV ในเครื่อง', 'vi': 'Máy chủ CalDAV cục bộ', 'id': 'Server CalDAV lokal', 'ms': 'Pelayan CalDAV tempatan'},
  'caldav_server_subtitle': {'de': 'Desktop-Kalender-Apps (Thunderbird/Outlook/Apple Kalender) mit dem Daemon verbinden — ohne externe Infrastruktur.', 'en': 'Connect desktop calendar apps (Thunderbird/Outlook/Apple Calendar) directly to the daemon — no external server.', 'es': 'Conectar apps de calendario de escritorio directamente con el daemon, sin infraestructura externa.', 'fr': 'Connecter les applications de calendrier de bureau directement au daemon, sans infrastructure externe.', 'hu': 'Asztali naptáralkalmazások (Thunderbird/Outlook/Apple Naptár) közvetlen csatlakoztatása a daemonhoz — külső infrastruktúra nélkül.', 'sv': 'Anslut skrivbordets kalenderappar (Thunderbird/Outlook/Apple Kalender) direkt till daemonen — utan extern server.', 'ar': 'ربط تطبيقات التقويم على سطح المكتب (Thunderbird/Outlook/Apple Calendar) مباشرةً بالـdaemon — دون بنية تحتية خارجية.', 'he': 'חיבור אפליקציות יומן במחשב (Thunderbird/Outlook/Apple Calendar) ישירות ל-daemon — ללא תשתית חיצונית.', 'fa': 'اتصال برنامه‌های تقویم دسکتاپ (Thunderbird/Outlook/Apple Calendar) مستقیماً به daemon — بدون زیرساخت خارجی.', 'it': 'Collega direttamente le app di calendario desktop (Thunderbird/Outlook/Apple Calendario) al daemon — senza infrastruttura esterna.', 'pt': 'Conecta apps de calendário de desktop (Thunderbird/Outlook/Apple Calendário) diretamente ao daemon — sem infraestrutura externa.', 'nl': 'Verbind desktop-agenda-apps (Thunderbird/Outlook/Apple Agenda) direct met de daemon — zonder externe infrastructuur.', 'pl': 'Połącz aplikacje kalendarza na komputer (Thunderbird/Outlook/Apple Kalendarz) bezpośrednio z daemonem — bez zewnętrznej infrastruktury.', 'ro': 'Conectează aplicațiile de calendar desktop (Thunderbird/Outlook/Apple Calendar) direct la daemon — fără infrastructură externă.', 'cs': 'Připoj desktopové kalendářové aplikace (Thunderbird/Outlook/Apple Kalendář) přímo k daemonu — bez externí infrastruktury.', 'sk': 'Pripoj desktopové kalendárové aplikácie (Thunderbird/Outlook/Apple Kalendár) priamo k daemonu — bez externej infraštruktúry.', 'hr': 'Poveži desktop kalendarske aplikacije (Thunderbird/Outlook/Apple Calendar) izravno s daemonom — bez vanjske infrastrukture.', 'bg': 'Свържи настолни календарни приложения (Thunderbird/Outlook/Apple Calendar) директно към daemon — без външна инфраструктура.', 'el': 'Σύνδεσε εφαρμογές ημερολογίου υπολογιστή (Thunderbird/Outlook/Apple Calendar) απευθείας στον daemon — χωρίς εξωτερική υποδομή.', 'da': 'Forbind desktop-kalenderapps (Thunderbird/Outlook/Apple Kalender) direkte til daemonen — uden ekstern infrastruktur.', 'fi': 'Yhdistä työpöydän kalenterisovellukset (Thunderbird/Outlook/Apple Kalenteri) suoraan daemoniin — ilman ulkoista palvelinta.', 'no': 'Koble skrivebords-kalenderapper (Thunderbird/Outlook/Apple Kalender) direkte til daemonen — uten ekstern infrastruktur.', 'uk': 'Під\\\'єднай настільні календарні застосунки (Thunderbird/Outlook/Apple Calendar) напряму до daemon — без зовнішньої інфраструктури.', 'ru': 'Подключи настольные календарные приложения (Thunderbird/Outlook/Apple Calendar) напрямую к daemon — без внешней инфраструктуры.', 'tr': 'Masaüstü takvim uygulamalarını (Thunderbird/Outlook/Apple Takvim) doğrudan daemon\\\'a bağla — harici altyapı olmadan.', 'zh': '将桌面日历应用（Thunderbird/Outlook/Apple 日历）直接连接到守护进程——无需外部基础设施。', 'ja': 'デスクトップのカレンダーアプリ（Thunderbird/Outlook/Apple カレンダー）を直接デーモンに接続します — 外部インフラ不要。', 'ko': '데스크톱 캘린더 앱(Thunderbird/Outlook/Apple 캘린더)을 데몬에 직접 연결합니다 — 외부 인프라 없이.', 'hi': 'डेस्कटॉप कैलेंडर ऐप्स (Thunderbird/Outlook/Apple Calendar) को सीधे daemon से कनेक्ट करें — बिना किसी बाहरी सर्वर के।', 'th': 'เชื่อมต่อแอปปฏิทินบนเดสก์ท็อป (Thunderbird/Outlook/Apple Calendar) เข้ากับ daemon โดยตรง — ไม่ต้องมีโครงสร้างภายนอก', 'vi': 'Kết nối trực tiếp ứng dụng lịch trên máy tính (Thunderbird/Outlook/Apple Calendar) với daemon — không cần hạ tầng bên ngoài.', 'id': 'Hubungkan aplikasi kalender desktop (Thunderbird/Outlook/Apple Calendar) langsung ke daemon — tanpa infrastruktur eksternal.', 'ms': 'Sambungkan aplikasi kalendar desktop (Thunderbird/Outlook/Apple Calendar) terus ke daemon — tanpa infrastruktur luaran.'},
